chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"add-to-vayo",title:"Add to VAYØ",contexts:["image","video"]})});chrome.contextMenus.onClicked.addListener(async(b)=>{if(b.menuItemId!=="add-to-vayo"||!b.srcUrl)return;let k=b.mediaType==="video"?"video":"image";await chrome.storage.local.set({pendingAsset:{url:b.srcUrl,assetType:k}});try{await chrome.action.openPopup()}catch{let j=await chrome.windows.getCurrent(),m=(j.left??0)+(j.width??1200)-420,q=j.top??40;chrome.windows.create({url:chrome.runtime.getURL("src/popup/popup.html"),type:"popup",width:400,height:420,left:m,top:q+40})}});
